// CLX Signal Ingestion v1 — Prep ingestion targets
// Returns one item per source; the downstream Split In Batches +
// HTTP Request iterates through them sequentially. Each source
// declares its URL + auth type + rate-limit note for operator
// awareness. URLs with ${ENV_VAR} placeholders are substituted at
// request time by n8n expressions against process.env.

const now = new Date();
const today = now.toISOString().split('T')[0];

const sources = [
  {
    source: 'gdelt',
    url: 'https://api.gdeltproject.org/api/v2/doc/doc?query=Canada%20insurance%20OR%20construction%20OR%20moving%20OR%20cleaning%20OR%20dental%20OR%20legal%20OR%20consulting%20OR%20real%20estate&mode=artlist&maxrecords=50&format=json&timespan=1hour',
    auth: 'none',
    rate_limit: 'none'
  },
  {
    source: 'newsapi_ca',
    url: 'https://newsapi.org/v2/top-headlines?country=ca&category=business&pageSize=50',
    auth: 'newsapi_credential',
    rate_limit: '100/day (free)'
  },
  {
    source: 'openweather_alerts_toronto',
    url: 'https://api.openweathermap.org/data/3.0/onecall?lat=43.6532&lon=-79.3832&exclude=hourly,minutely',
    auth: 'openweather_credential',
    rate_limit: '1000/day (free)'
  },
  {
    source: 'boc_fx_rates',
    url: 'https://www.bankofcanada.ca/valet/observations/FXUSDCAD,FXEURCAD,FXGBPCAD/json?recent=7',
    auth: 'none',
    rate_limit: 'none'
  },
  {
    source: 'boc_interest_rate',
    url: 'https://www.bankofcanada.ca/valet/observations/V80691311/json?recent=30',
    auth: 'none',
    rate_limit: 'none'
  },
  {
    source: 'fsra_regulatory_feed',
    url: 'https://www.fsrao.ca/news-and-information/news/rss',
    auth: 'none',
    rate_limit: 'none',
    format: 'rss'
  },
  {
    source: 'google_trends_verticals',
    url: 'PLACEHOLDER',
    auth: 'none',
    rate_limit: 'requires pytrends server or SerpAPI — deferred',
    skip: true
  }
];

// Filter skips; emit one item per active source
return sources.filter(s => !s.skip).map(s => ({ json: { ...s, today } }));

// CLX Signal Ingestion v1 — Normalize per-source payload
// Converts each source's response into an array of canonical raw-
// signal items ready to insert into market_signals_raw. Every source
// has its own parsing path; unknown sources emit zero items (no-op).
// Bad/empty responses emit zero items; errors are logged but don't
// fail the pipeline.

const source = $('Split In Batches').item.json.source;
const payload = $input.item.json || {};
const httpError = payload.error || (payload.message && payload.code) || null;

if (httpError) {
  return [{ json: { source, _error: true, _error_msg: String(httpError).slice(0, 300), items: [] } }];
}

const nowIso = new Date().toISOString();
const items = [];

try {
  switch (source) {
    case 'gdelt': {
      const articles = Array.isArray(payload.articles) ? payload.articles : [];
      for (const a of articles.slice(0, 50)) {
        if (!a || !a.url) continue;
        items.push({
          source: 'gdelt',
          external_id: a.url,
          raw_payload: a,
          raw_url: a.url,
          fetched_at: nowIso
        });
      }
      break;
    }
    case 'newsapi_ca': {
      const articles = Array.isArray(payload.articles) ? payload.articles : [];
      for (const a of articles.slice(0, 50)) {
        if (!a || !a.url) continue;
        items.push({
          source: 'newsapi_ca',
          external_id: a.url,
          raw_payload: a,
          raw_url: a.url,
          fetched_at: nowIso
        });
      }
      break;
    }
    case 'openweather_alerts_toronto': {
      const alerts = Array.isArray(payload.alerts) ? payload.alerts : [];
      for (const a of alerts) {
        if (!a || !a.event) continue;
        items.push({
          source: 'openweather_alerts_toronto',
          external_id: (a.event || 'unknown') + '_' + (a.start || nowIso),
          raw_payload: a,
          raw_url: null,
          fetched_at: nowIso
        });
      }
      break;
    }
    case 'boc_fx_rates':
    case 'boc_interest_rate': {
      // One aggregate signal per day per source; BoC observations are
      // small enough to embed whole
      const today = new Date().toISOString().split('T')[0];
      items.push({
        source,
        external_id: source + '_' + today,
        raw_payload: payload,
        raw_url: null,
        fetched_at: nowIso
      });
      break;
    }
    case 'fsra_regulatory_feed': {
      // RSS parsing is not in-scope for a Code node; we persist the raw
      // XML as a single signal per 24h and let the Intelligence worker
      // parse it via Claude's text reasoning.
      const today = new Date().toISOString().split('T')[0];
      const rawText = typeof payload === 'string' ? payload : (payload.body || JSON.stringify(payload));
      items.push({
        source,
        external_id: 'fsra_' + today,
        raw_payload: { format: 'rss_xml_raw', text: String(rawText).slice(0, 50000) },
        raw_url: 'https://www.fsrao.ca/news-and-information/news/rss',
        fetched_at: nowIso
      });
      break;
    }
    default: {
      // Unknown source; emit nothing
      break;
    }
  }
} catch (e) {
  return [{ json: { source, _error: true, _error_msg: e.message || String(e), items: [] } }];
}

if (items.length === 0) {
  return [{ json: { source, _empty: true, items: [] } }];
}

return items.map(i => ({ json: i }));

// CLX Signal Ingestion v1 — Summarize run
// Returns a single summary row: total items ingested, per-source
// counts, errors observed. Also writes a lightweight audit entry to
// admin_action_log (vertical_generated placeholder action_type until
// the enumeration is extended).

const all = $('Normalize Payload').all();
const counts = {};
let totalItems = 0;
let errors = 0;

for (const it of all) {
  const src = it.json.source || 'unknown';
  counts[src] = (counts[src] || 0) + 1;
  if (it.json._error) errors += 1;
  else if (!it.json._empty) totalItems += 1;
}

return { json: {
  total_items: totalItems,
  per_source: counts,
  errors,
  run_at: new Date().toISOString()
} };
